mapper.select:
/* com.educare.edu.comn.mapper.LectureSubjectMapper.selectByList */
	select a.* from t_lecture_subject a 
	where 1=1
	 and state = #{state}

mapper.update:
/* com.educare.edu.comn.mapper.LectureSubjectMapper.updateByPk */
	update t_lecture_subject
	set upd_id = #{updId} , upd_de=#{updDe}
	 		,sub_nm 		= #{subNm} 
	 	,pass_cert_nm 		= #{passCertNm} 
	 ,compl_cert_nm 		= #{complCertNm} 
	 		,pass_idx		= #{passIdx} 
	 		,compl_idx		= #{complIdx} 
	 			,state			= #{state} 
	where sub_seq=#{subSeq}

mapper.select:
/* com.educare.edu.comn.mapper.LectureSubjectMapper.selectLctreTimeSubList */
	select a.* from t_lecture_subject a
	where sub_seq in (select sub_seq from t_lecture_time where edu_seq = #{eduSeq})
